verifyRazorpaySignature = (orderId, paymentId, signature) => {
  const body = orderId + '|' + paymentId;
  const expectedSignature = crypto
    .createHmac('sha256', env.RAZORPAY_KEY_SECRET)
    .update(body.toString())
    .digest('hex');

  return expectedSignature === signature;
}

verifyWebhookSignature = (rawBody, signature) => {
  if (!env.RAZORPAY_WEBHOOK_SECRET) {
    if (process.env.NODE_ENV === 'production') {
       throw new Error('CRITICAL: RAZORPAY_WEBHOOK_SECRET is missing in production environment.');
    }
    console.warn('WARNING: RAZORPAY_WEBHOOK_SECRET is missing. Skipping signature check in non-production mode.');
    return true; 
  }

  const expectedSignature = crypto
    .createHmac('sha256', env.RAZORPAY_WEBHOOK_SECRET)
    .update(rawBody)
    .digest('hex');

  return expectedSignature === signature;
}

formatMessage = (level, message, meta = {}) => {
  const timestamp = new Date().toISOString();
  if (isProd) {
    return JSON.stringify({
      timestamp,
      level,
      message,
      ...meta,
    });
  }

  const metaStr = Object.keys(meta).length ? ` | ${JSON.stringify(meta)}` : '';
  const colors = {
    info: '\x1b[32m', // Green
    warn: '\x1b[33m', // Yellow
    error: '\x1b[31m', // Red
    reset: '\x1b[0m',
  };

  const color = colors[level] || colors.reset;
  return `${timestamp} ${color}${level.toUpperCase()}${colors.reset}: ${message}${metaStr}`;
}

